target.css:
:root {
  --card-bg: #1e1b2e;
  --cover-bg: #6c47ff;
  --cover-accent: #a78bfa;
  --play-bg: #ffffff;
  --play-color: #6c47ff;
  --tag-bg: #6c47ff;
  --tag-color: #ffffff;
  --title-color: #f1eeff;
  --show-color: #a78bfa;
  --desc-color: #c4b8f0;
  --track-bg: #3b3560;
  --fill-color: #6c47ff;
  --time-color: #7c6fa0;
  --pill-bg: #2e2a45;
  --pill-color: #c4b8f0;
  --btn-bg: #6c47ff;
  --btn-color: #ffffff;
  --card-radius: 16px;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.podcast-card {
  background: var(--card-bg);
  border-radius: var(--card-radius);
  padding: 20px;
  width: 100%;
  max-width: 500px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.podcast-header {
  display: flex;
  flex-direction: row;
  gap: 16px;
  align-items: flex-start;
}

.cover-art {
  width: 88px;
  height: 88px;
  min-width: 88px;
  background: var(--cover-bg);
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.cover-art::before {
  content: '';
  position: absolute;
  width: 100px;
  height: 100px;
  border-radius: 50%;
  background: var(--cover-accent);
  opacity: 0.25;
  top: -30px;
  right: -30px;
}

.play-btn {
  width: 36px;
  height: 36px;
  background: var(--play-bg);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--play-color);
  font-size: 14px;
  padding-left: 2px;
  position: relative;
  z-index: 1;
}

.podcast-meta {
  display: flex;
  flex-direction: column;
  gap: 6px;
  flex: 1;
}

.category-tag {
  background: var(--tag-bg);
  color: var(--tag-color);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  padding: 3px 8px;
  border-radius: 4px;
  align-self: flex-start;
}

.episode-title {
  color: var(--title-color);
  font-size: 15px;
  font-weight: 700;
  line-height: 1.3;
  margin: 0;
}

.show-name {
  color: var(--show-color);
  font-size: 12px;
  font-weight: 500;
  margin: 0;
}

.episode-desc {
  color: var(--desc-color);
  font-size: 13px;
  line-height: 1.6;
  margin: 0;
}

.podcast-footer {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.progress-wrap {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-bar {
  width: 100%;
  height: 4px;
  background: var(--track-bg);
  border-radius: 2px;
  overflow: hidden;
}

.progress-fill {
  width: 34%;
  height: 100%;
  background: var(--fill-color);
  border-radius: 2px;
}

.time-labels {
  display: flex;
  justify-content: space-between;
  color: var(--time-color);
  font-size: 11px;
}

.footer-actions {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 8px;
}

.stat-pill {
  background: var(--pill-bg);
  color: var(--pill-color);
  font-size: 12px;
  font-weight: 500;
  padding: 5px 12px;
  border-radius: 20px;
}

.subscribe-btn {
  margin-left: auto;
  background: var(--btn-bg);
  color: var(--btn-color);
  border: none;
  border-radius: 8px;
  padding: 8px 20px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
}

